<?php require_once 'db.php'; verify_csrf(); $err=''; if($_SERVER['REQUEST_METHOD']==='POST'){ $email=filter_input(INPUT_POST,'email',FILTER_VALIDATE_EMAIL); $pass=$_POST['password']??''; $st=pdo()->prepare('SELECT u.*,r.name role FROM users u JOIN roles r ON r.id=u.role_id WHERE u.email=? AND u.status="active"'); $st->execute([$email]); $u=$st->fetch(); if($u && password_verify($pass,$u['password'])){ session_regenerate_id(true); $_SESSION['user']=['id'=>$u['id'],'name'=>$u['name'],'email'=>$u['email'],'role'=>$u['role']]; log_activity($u['id'],'Logged in'); redirect_by_role($u['role']); } else $err='Invalid credentials or blocked account.'; } app_header('Login'); ?>
<section class="auth card"><h1>Login</h1><p class="error"><?=e($err)?></p><form method="post"><?=csrf_field()?><input name="email" type="email" placeholder="Email" required><input name="password" type="password" placeholder="Password" required><button class="btn">Login</button></form><a href="forgot_password.php">Forgot password?</a></section><?php app_footer(); ?>
